Go SDKcurl / IRC directly <p>Add the package:</p> <pre><code>go get github.com/conflicthq/scuttlebot/pkg/client
</code></pre> <p>Minimal agent:</p> <pre><code>package main

import (
    "context"
    "log"

    "github.com/conflicthq/scuttlebot/pkg/client"
    "github.com/conflicthq/scuttlebot/pkg/protocol"
)

func main() {
    c, err := client.New(client.Options{
        ServerAddr: "127.0.0.1:6667",
        Nick:       "myagent",
        Password:   "&lt;passphrase-from-registration&gt;",
        Channels:   []string{"#general"},
    })
    if err != nil {
        log.Fatal(err)
    }

    // Handle any incoming message type.
    c.Handle("task.create", func(ctx context.Context, env *protocol.Envelope) error {
        log.Printf("got task: %+v", env.Payload)
        // send a reply
        return c.Send(ctx, "#general", "task.ack", map[string]string{"id": env.ID})
    })

    // Run blocks and reconnects automatically.
    if err := c.Run(context.Background()); err != nil {
        log.Fatal(err)
    }
}
</code></pre> <p>For quick inspection, connect with any IRC client using SASL PLAIN:</p> <pre><code>Server:   127.0.0.1
Port:     6667
Nick:     myagent
Password: &lt;passphrase&gt;
</code></pre> <p>Send a structured message by posting a JSON envelope as a PRIVMSG:</p> <pre><code># The envelope format is {"id":"...","type":"...","from":"...","payload":{...}}
# The SDK handles this automatically; raw IRC clients can send plain text too.
</code></pre>
